import { useState, useEffect, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  LayoutDashboard,
  ShoppingCart,
  Users,
  Package,
  BarChart3,
  Settings,
} from "lucide-react";

import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const menuItems = [
  { name: "Dashboard", icon: LayoutDashboard },
  { name: "Products", icon: Package },
  { name: "Orders", icon: ShoppingCart },
  { name: "Users", icon: Users },
  { name: "Analytics", icon: BarChart3 },
  { name: "Settings", icon: Settings },
];

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState("");

  // Auto open sidebar on large screens
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) setIsOpen(true);
      else setIsOpen(false);
    };

    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // Filter menu
  const filteredMenu = useMemo(() => {
    return menuItems.filter((item) =>
      item.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [search]);

  return (
    <div className={design.layout.wrapper}>

      {/* 🔥 TOP NAVBAR (Common Header Area) */}
      <div className={design.layout.navbar}>

        <div className="flex items-center gap-4">
          {/* Mobile toggle */}
          <button
            onClick={() => setIsOpen(!isOpen)}
            className="lg:hidden text-gray-700 text-xl"
          >
            ☰
          </button>

          {/* Common Title */}
          <h1 className={design.colors.title}>
            Admin Panel
          </h1>
        </div>

        {/* Search */}
        <input
          type="text"
          placeholder="Search menu..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className={design.colors.input}
        />

        {/* Admin info */}
        <div className="flex items-center gap-3">
          <span className="text-sm text-gray-600">
            {adminInfo?.name}
          </span>
          <div className="w-8 h-8 bg-indigo-500 rounded-full"></div>
        </div>
      </div>

      {/* 🔥 BODY */}
      <div className={design.layout.body}>

        {/* Sidebar */}
        <AnimatePresence>
          {isOpen && (
            <motion.aside
              initial={{ x: -260 }}
              animate={{ x: 0 }}
              exit={{ x: -260 }}
              transition={{ duration: 0.3 }}
              className={`${design.colors.sidebar} ${design.layout.sidebar} fixed lg:static h-full z-50`}
            >
              <nav className="space-y-2">
                {filteredMenu.length > 0 ? (
                  filteredMenu.map((item, index) => {
                    const Icon = item.icon;
                    return (
                      <div
                        key={index}
                        className={`${design.layout.navItem} ${design.colors.hover}`}
                      >
                        <Icon size={18} />
                        {item.name}
                      </div>
                    );
                  })
                ) : (
                  <p className="text-sm text-gray-500">No results</p>
                )}
              </nav>
            </motion.aside>
          )}
        </AnimatePresence>

        {/* Overlay */}
        {isOpen && window.innerWidth < 1024 && (
          <div
            className={`fixed inset-0 ${design.colors.overlay} z-40`}
            onClick={() => setIsOpen(false)}
          />
        )}

        {/* Content */}
        <div className={design.layout.content}>
          <motion.div
            initial={{ opacity: 0, y: 15 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <h2 className="text-2xl lg:text-3xl font-bold mb-4">
              Welcome Back 👋
            </h2>

            <p className="text-gray-600">
              Professional dashboard with shared header, icons, and searchable sidebar.
            </p>
          </motion.div>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;
